(window.webpackJsonp=window.webpackJsonp||[]).push([[26],{291:function(v,_,p){"use strict";p.r(_);var t=p(13),a=Object(t.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("h1",{attrs:{id:"金陵往事"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#金陵往事"}},[v._v("#")]),v._v(" 金陵往事")]),v._v(" "),_("h2",{attrs:{id:"缘恋终结"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#缘恋终结"}},[v._v("#")]),v._v(" 缘恋终结")]),v._v(" "),_("p",[v._v("致敬 三载青春的谢幕")]),v._v(" "),_("p",[v._v("如果执着终归于徒然，谁会将此生用尽，只为守候一段触摸不得的缘恋？如果多年的执念，就此放下、隔断，是否会有眼泪倾洒，以为祭奠？纵然贵为神尊，也会羽化而湮灭。虽是女君，亦会消逝在时光悠然间。只是不知，当风云淡去，当仍在无羁岁月间穿行，当偶有擦肩。我还能记起她们吗？还能否记起曾经，她们是什么模样呢？酷暑的阳光烧灭那一切的思念，从前的一切与我再无关联。")]),v._v(" "),_("p",[v._v("三月草长，四月莺飞，五月花落，六月树成。而到了七月流火时节，十里桃林千层锦绣花已繁华谢尽。三生三世轮回，谁知缘分何在？ 枕上书下，泪落席边。凉凉月色，却是为你，思念成河。时间长久，可记忆可曾永存？过去的一切，从此完结。静谧的深邃的夜色里，小雨淅沥。不知不觉，碑亭巷的日子，就此告一段落了。三年的一切打上了往事的标签，塞进了回忆的格子里。快乐的、悲伤的、痛苦的、幸福的......都不在了；当年我想的、我念的那个人，也许，再也不会，在我的生命中出现了。")]),v._v(" "),_("p",[v._v("接下来，那江南小城宣州里的日子，将是生命里崭新的篇章。谁也不清楚命中那真正注定的她，究竟是谁，又究竟在何处。此时我想的，我念的人，与我，随着时间的流逝，终归渐行，渐远。虽然，我仍记得那个会让我心中怦然一动的名字，但我却渐渐忘记了那深深印在心底的容颜。虽然，我仍记得那个使得我魂牵梦绕的地方，但我却再也没有了前往那里的勇气。点滴甘霖，权当做，对那里，对她，最后的留恋。且抛下过去的所有，把回忆深藏，让那些心灵的羁绊远去，让那所有的心结幻灭。")]),v._v(" "),_("p",[v._v("当梦永远结束的时候，现实的惨淡笼罩回心头。这时，偏见可以放下，怨愤化为平淡。曾经写下的一切，真假难辨；曾经有过的真相，早已不见。谁曾爱过谁，谁曾陪伴谁？这早已不重要。前途里风霜雨雪无数，他们，终将会被残忍的分离。也许就此，永世难聚。假若登上那高耸入云的大山，站在山顶一看，世间一切都渺小至斯，儿女情伤不过是天边的浮云，一挥手便可抹去。假若投身那飞流直下的瀑布，随他奔腾入河川，不舍昼夜，便从不回头。人生亦是如此，不能回头，总是要向前看。凉凉夜色里，多少为思念而留下的眼泪，终归是无妄的悲伤。")]),v._v(" "),_("p",[v._v("凡人，能在世上走的不过数十载春秋，受司命排的种种命格所困，种田的大多一生穷苦，读书的大多志不能展，深闺的好儿女难觅佳偶，可他们仍欢欢喜喜的过着。诚哉斯言！在苍天面前，一切都是浮云，再深的爱恋不过如此，点滴往事又从何寻觅？三生三世的记忆如此漫长，三生三世的爱恋却又痛苦。只愿有朝一日，在梦境里，她转过头来，风拂过，树上的烟霞起伏成一波红色的海浪。她微微一笑，仍是初见的模样，如画的眉眼，漆黑的发。红色的海浪中飘下几朵花瓣，天地间再没有其他的色彩，也没有其他的声音了。如此，便是极好。")]),v._v(" "),_("p",[v._v("缘之一物即是如此，没有什么是天注定的。每一秒的选择，都决定着你进入的时空。所谓四维，也许便是那平行的无数三维时空。你所做的每一个选择，都把你带入了不同的三维时空。若是当年，鼓起勇气表白，未来会是如何？若是当年，奋发图强向上，未来会是如何？一切尽成过往，不可能重来。若是那时，不去选择放下，前程是否迷茫？故乱世，方有英雄；故英雄，方有佳人；奈何纷乱，奈何纷乱。故嗜兵，方成盛名；故盛名，方不厌诈；兵不厌诈，兵不厌诈。故飞燕，方惹多情；故多情，方害相思；一望成欢，一望成欢。故春盈，方恨秋思；故秋思，方恨离情；不离不弃，不离不弃。")]),v._v(" "),_("p",[v._v("秋思之时，离情别意，重上心头。转瞬间，一切尘埃落定。中元节至，往事终将告别。皖南大地上，又是全新的一切。而她，却已在数百里外。长江之畔，黄海之滨的启东，未尝不是一个好去处。愿，能再遇一个如她一般的女子，将她忘却；又愿，再不遇见如她一般的女子，让我痴迷，又让我痛苦。神思不属，衣带渐宽。却终不悔，为伊消得人憔悴。淮阳，已不可忘却，只得让她长留心底，让时光的过去淡去那所有的思念。一切已成往事，而往事难再。")]),v._v(" "),_("p",[v._v("淮水之阳，她的故乡。一望成欢，即是淮阳。又是一年隆冬，雪景尤胜当年。然而，人已不再。雪花飞舞的日子里，忆起，过往，如今。在你生命中最美好的三年里，我，有幸，遇见了你。")]),v._v(" "),_("h2",{attrs:{id:"往事如烟"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#往事如烟"}},[v._v("#")]),v._v(" 往事如烟")]),v._v(" "),_("p",[v._v("致 平淡而美好的昨天")]),v._v(" "),_("p",[v._v("光华路，金陵城东南的主干路之一。十年之间，这条路，一次又一次踏过。不同的是，如今，这里的繁华已经谢尽。城市的发展中，总有兴衰几处。曾经的富庶之地，在失意之后，逐渐开始焕发新的生机。往事如烟，在那友谊河的水里渐渐散去。时光匆匆，这里，见证了一切的变换，从开头，到结束。")]),v._v(" "),_("p",[v._v("那故事的开头，七载岁月，在那龙宫路上挥霍。漫长的时光之中，一切让那黑暗笼罩。每一段友情都总是很短暂，匆匆而来然后又匆匆而去。曾经有过的短暂光明，曾经出现的那善良可爱的女孩，在昙花一现的爱意之后重又消散。七年时光，如生活在迷雾之中，前途一片朦胧。那寻不得的，或许，不仅仅是自由。")]),v._v(" "),_("p",[v._v("穿插在那悠远时光里的，是南京理工大学的校园。许许多多的人进进出出，但是只有少数的幸运儿，得以真正迈入。春，这里是绚烂的花海；夏，这里有泛滥的水灾；秋，金色的落叶遍布成排；冬，一切只剩下白雪皑皑。这里，是孝陵卫皇家理工。求学者可往，享乐者莫来。")]),v._v(" "),_("p",[v._v("时光悠然。挥别东郊，走入那繁华的城市中央。穿过那碑亭巷口，来到那织造府旁。不同于那过去的无奈与彷徨，此处的日子，多了许多别样的精彩。情与爱，悲与喜，苦与乐，百味杂陈。怀念总伴随着感伤，怨忿也尽归于平淡。花谢了，还会再开；人散了，不能重来。阴霾散去，生活的曙光重又来到心头。")]),v._v(" "),_("p",[v._v("在那最失意最困惑的时光里，她，走进了我的生活，走入我的心上。如果说，你是海上的烟火，我是浪花的泡沫。这一刻，你的光照亮了我。我从此跟在你身后，像影子追着光梦游。而光，就在这里。城市的北郊，再看那熟悉的楼宇。可是一切，都已经改变。失去的，不会重来。")]),v._v(" "),_("p",[v._v("如果说，淮阳是那遥远的星河，而我是追随着她的眼眸。那么，你则是那追随路上的和煦春风。似乎，你的脸上总是那淡淡的笑容，纵使生气，纵使悲伤，依旧是可爱的模样。你，我心中那最温婉的女子，最终去到了我心中那最温婉的城，融入进，那江南水乡的一切之中。")]),v._v(" "),_("p",[v._v("追逐着那星河的我，不复那曾经的怅惘无助。无论世事更迭，无论风霜雨雪，只要看见那俏颜，便能激励着勇往直前。那潇洒的身姿，那飘飞的长发，那含笑的眼眸。感谢，一路有你，让那心灵，在艰苦岁月里保持生机。而今，星河已远，何处觅前途？")]),v._v(" "),_("p",[v._v("星河，终究太远。她与我，毕竟不是一路之人。虽说开头无法预料，但结局早已注定。那最后的时光之中，伴随着我的，是那和煦的春风。夜晚的小巷，她骑着小车，默默出现在那视野里，又渐渐抹去。深夜的课堂，她执着的坚守，默默伴随着我。虽说故事从未有过，那也只是因为，非分的念想当归于沉默。")]),v._v(" "),_("p",[v._v("星河之外，亦有无数微光。春风化雨，留作甘霖点滴。除却那曾留下念想的人们，许多人，也曾或多或少来到过那心间。遍游金陵城里，寻找记忆，回想，他们那时的点点滴滴。多少年后，当他们的样貌逐渐在脑海里淡却，他们的名字沦为陌生，那失落的记忆，该如何找寻？")]),v._v(" "),_("p",[v._v("青春里，总少不了一个跃动而叛逆的身影。墙头那一次又一次的一跃而过，406和基佬屋里不时闪动着的荧光。你，在这里。再多的约束约束不了一颗自由的心，再严的规章制服不了一个自由的人。犹记，讲台边，你那肆意妄为的样子。")]),v._v(" "),_("p",[v._v("然而，不是所有人都能屡战屡胜。总有那么一些人，为着那叛逆的一举一动而付出代价。但是，既然已经开始，那便一去不回。多少过错，尽管承担便是，他，无所畏惧。这，是骄傲的龙城君。游走那无数暖香温玉般的怀抱，拈花惹草之间，却不带走，一丝尘土。")]),v._v(" "),_("p",[v._v("叛逆并不是生活的全部，低调里略带几分闷骚，同样是一种生活态度。男子汉外表之下，是一颗萌萌的狐狸心。爱音乐，更爱生活。无论生活怎样对待，都坚持乐观向上。爱阅读，也爱运动。学习如同球场之上，不到结尾，绝不服输。成败得失，早已不重要。")]),v._v(" "),_("p",[v._v("吉他，是那自由的号角。音乐，则是那律动的人生。热爱音乐的你，将那潇洒尽情展现。让自己成为那人群的焦点，过那不一样的人生。独在异乡为客的你，趁那东湖夜色宜人，且在那光与影的交错里奏起，属于自己的乐章。")]),v._v(" "),_("p",[v._v("太平门，向东是紫金山，向西是玄武湖。一头是沉稳庄重，一头是活泼灵动。他，像山一样，在无数的风霜里，巍然不动。纵天崩地裂，我自安然。若是找寻到那正确的人并追随，你将前程似锦。而她，像水一样，流过无数的怀抱，却停不住那流失的步伐。姣好面容收获无数的目光，却充实不了你的胸膛。塞北苦寒，愿一路安好。")]),v._v(" "),_("p",[v._v("九华山，湖畔有山，山上有庙，庙藏舍利。珍贵的东西，往往看上去平淡无奇。那忠厚老实的长者，平平无奇而奋发努力，纵未有所成，终归曾经奋斗。那时常盘旋他身侧的女子，虽不算是佳丽，却也深受爱护几重。不曾多少垂涎美色，却有几许喜爱性格。生活苦难，安于平凡，却在平凡之中，成就了那不平凡的自己。")]),v._v(" "),_("p",[v._v("珠江路，从这头到那头，春风十里。多少故事从这里开始，多少故事在这里终结。贯穿在这道路之上的，是那活泼的精灵，和那多少女子的密友。活泼的精灵来到那江北大地，让那青春的身影给无数人以生机；女子的密友来到姑苏城外，小镇周庄有着不一样的水乡韵味。她的可爱，有着那不一样的感觉。他的善良，使人想要去亲近。他们，依然安好。")]),v._v(" "),_("p",[v._v("西湖的无尽烟云，最终落在了那紫金山中的深处；城南的多少古朴，终于停在了那异国他乡的角落。昔年那未能再进一步的故事，在梦里告终。他，度过春夏秋冬，与那不算太美好的念想，失之交臂于那七月的午后。她，历经秋冬春夏，却仍是当年模样，倩影依稀。然而，无论世事如何变换，那善良却仍是不减当年，多了的，只不过是岁月沧桑。")]),v._v(" "),_("p",[v._v("终于，金陵的故事走到了尽头。西家大塘那清脆的铃声，为这十载金陵的时光画上了句号。回到那碑亭巷口的日子，重新体会，那时单纯的小美好。沉浸于书山题海之中，披星戴月，看那排行榜上起起落落。这，其实也是一种幸福。")]),v._v(" "),_("p",[v._v("金陵春朝绿树密，石城清明红花稀。烟笼秦淮云遮月，雾锁长江涛掩笛。玄武莫愁不见底，栖霞幕府能隐谜。甲午乙未俱往矣，丙申丁酉怀往昔。转眼，戊戌年又近在眼前了。时光，如此匆忙，如此残酷。忘却吧，那遥远的夏天。")]),v._v(" "),_("h2",{attrs:{id:"前程似锦"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#前程似锦"}},[v._v("#")]),v._v(" 前程似锦")]),v._v(" "),_("p",[v._v("致 那灿烂而精彩的未来")]),v._v(" "),_("p",[v._v("金陵的故事，在那个夏天走到了终点。宣州的九月，剧本翻到了新的一页。人生漫漫，不能总是纠结于过往的旅途。毕竟，时光的世界里，从没有回头路。旧人已去，那全新的剧本里，渐渐失去了他们的踪迹。新的故事，将会有新的演员来上演。大幕重新拉开，那全新的故事，才刚刚开始。")]),v._v(" "),_("p",[v._v("有的朋友，看似亲密却实则疏离；有的朋友，淡如清茶却回味无尽。不是所有人都喜爱尘世浮华与喧嚣，午后在阳光的沐浴下捧一本书一杯清茶，也是别样的韵味。漫步，不必如运动会上般的争分夺秒；交谈，不必如辩论场上般的唇枪舌剑。走在那校园的四处，谈天论地，温暖的时光里，是那小小的幸福。")]),v._v(" "),_("p",[v._v("每个人的身边，都有着一个非凡的人物。不论看上去多么寻常，时光终将揭露那大佬的面目。大佬，不一定非得门门精通，不一定非要文武双全，但是身为大佬必有那属于大佬的过人之处。大佬们也许同样会沉迷游戏，但那游戏之余的时光必定精彩纷呈。大佬们也许同样会为我们苦恼的事物而苦恼，但苦恼之余他依然能交上完美的答卷。大佬也许看似平庸，但总有一刻会发出耀眼的光芒。")]),v._v(" "),_("p",[v._v("星河，已经消失在了远方。明朗的月亮，在那夜空里浮现。明月当空，那是多少仰视目光的焦点。无数人奔走在那追寻月亮的路上，无数人痴迷于那月亮的神秘光芒。那区区飞蛾，又怎敢对那月光有所奢望？那高挑的美丽的仙子啊，不必在意来自小小蝼蚁的向往。灯火阑珊处已成奢望，何况是那照耀大地的月光？不思，不想。没有念想，也就没有失望。")]),v._v(" "),_("p",[v._v("飞蛾扑火，向着的也许只是微光。那月下的灯影扑朔，但在那乍然亮起的刹那，那光明的感觉直入那心头。到了那深夜时分，灯光已平平淡淡，但那晚归的旅人，仍能从中得到那别样的温暖。无需多么美丽，无需多么亮眼。在那灯火阑珊的时候，一缕光芒，也是那温暖的记号。")]),v._v(" "),_("p",[v._v("你若有光，便在远方，念念不忘，必有回想。不知道那是一个怎样的故事，不知道那是一个怎样的人。但能让那样的人物念念不忘的，想必也不是凡夫俗子。多少打击摧毁不了你，多少挫败伤害不了你。你，文武双全，一表人才，是那万千凡夫俗子里鹤立鸡群的存在。阴差阳错间，你来到这里，是不幸，也是幸运。跌落凡尘，也许，只是为了让你历练自我，成就更非凡的自己。淮畔珠城，你在这里。")]),v._v(" "),_("p",[v._v("悠远的萨克斯声回荡，那温情的乐曲需要那温情的人来演奏。长江之水养育着那三峡儿女，让那多少英才散布各方。也许他们不算非凡，也许他们并非骄子，但他们总可称得上大佬一词。人群之中，他们不是那最优秀的一个，但他们永远在那拔尖的一群。无论前方多少难关阻挡，他总能自由飞翔。在那不起眼的角落里，大佬，总在闪闪发光。")]),v._v(" "),_("p",[v._v("诚然，不是每一个人都能成为大佬，也不是每一个人都是造化钟神秀的英才。人群之中，更多的还是普普通通的大多数。他们不像大佬们一样吸引着无数目光，但他们可以做不一样的自己。既然不能成为人群的中心，那便成为人群里那最独特的身影。健身使人亢奋，音乐使人温柔，读书使人明智，动漫使人纯真。不必在意外界打扰，做你自己就好。")]),v._v(" "),_("p",[v._v("风，吹开了记忆的锁，想起旧时的你我。星河无处追随，姑苏城里的春风也已无觅。这时，那遥远的北方却吹来了那清新的空气。那大草原的风啊，你在那彷徨无措的岁月里降临，把那多少感伤的故事，化为那遥远的回忆。风，一直在那里。时而轻柔，时而凌厉。吹拂那旷野之上的我，让前途在迷茫里继续下去。无所谓情，也许这只是一点感激。")]),v._v(" "),_("p",[v._v("与明月相伴的，是那天空的云彩。它们是天空中飞舞的精灵，不时遮蔽那属于月亮的光华。夜空下的它们平平无奇，丝毫不曾引起那众人的目光，但待到那东方的苍穹渐渐发白，天空展现那无数的光彩。云，便在碧蓝的天地里幻化作无数情状。时而轻柔舒缓，时而凌空飘飞，变化万端，绚丽动人。欣赏那多变的云，更欣赏那云一样多变的你。")]),v._v(" "),_("p",[v._v("燕赵大地，多的是那慷慨激昂的义士。豪爽不羁，自由奔放。纵使生活不曾盛情待我，我依然乐观待它。不介意风云变幻，不在意起起伏伏，我只做我自己。若是能成为大佬，那便去做，人群的称赞不是不好。成不了大佬，那也无妨，我就是我，是不一样的烟火。纵情饮酒，纵情高歌，只要自己快乐，一切便是极好，夫复何求？")]),v._v(" "),_("p",[v._v("人生的旅途，如同乘坐着一班又一班的列车。列车有快有慢，座位有前有后。而在那中转站里，你踏入的列车，决定了你前行的方向。每一趟车上，你会遇见不同的人，有的只是匆匆过客，而有的可能相伴一生。所有的相逢都是缘分，纵使他有再多不是，纵使相处再多苦闷，到了那离别的日子，终究会有那么几分伤感。忘记曾经的一切，致敬美好的未来。")])])}),[],!1,null,null,null);_.default=a.exports}}]);